// Stateful: owns the state, then delegates UI to the stateless version.
@Composable
fun Counter() {
  var count by remember { mutableStateOf(0) }
  CounterContent(
    count = count,
    onIncrement = { count++ }   // event flows UP; new state flows back DOWN
  )
}

// Stateless: UI = f(state). Pure description, fully reusable + previewable.
@Composable
fun CounterContent(
  count: Int,
  onIncrement: () -> Unit,
  modifier: Modifier = Modifier
) {
  Column(modifier.padding(16.dp)) {
    // Reading `count` here subscribes this Text to it.
    // When count changes, only this scope recomposes.
    Text("Count: $count", style = MaterialTheme.typography.headlineSmall)
    Spacer(Modifier.height(8.dp))
    Button(onClick = onIncrement) {
      Text("Increment")
    }
  }
}

