data class SearchUiState(
  val query: String = "",
  val results: List<String> = emptyList()
)

class SearchViewModel : ViewModel() {
  private val _uiState = MutableStateFlow(SearchUiState())
  val uiState: StateFlow<SearchUiState> = _uiState.asStateFlow()

  fun onQueryChange(query: String) {
    _uiState.update { current ->
      current.copy(
        query = query,
        results = searchRepository.search(query)
      )
    }
  }
}

@Composable
fun SearchRoute(
  viewModel: SearchViewModel = viewModel(),
  onResultClick: (String) -> Unit
) {
  val uiState by viewModel.uiState.collectAsStateWithLifecycle()

  SearchScreen(
    uiState = uiState,
    onQueryChange = viewModel::onQueryChange,
    onResultClick = onResultClick
  )
}

@Composable
fun SearchScreen(
  uiState: SearchUiState,
  onQueryChange: (String) -> Unit,
  onResultClick: (String) -> Unit,
  modifier: Modifier = Modifier
) {
  Column(modifier) {
    OutlinedTextField(
      value = uiState.query,
      onValueChange = onQueryChange,
      modifier = Modifier.fillMaxWidth(),
      label = { Text("Search") },
      singleLine = true
    )

    LazyColumn {
      items(uiState.results, key = { it }) { result ->
        ListItem(
          headlineContent = { Text(result) },
          modifier = Modifier.fillMaxWidth()
        )
      }
    }
  }
}

@Composable
fun ModifierOrderDemo() {
  Column(
    modifier = Modifier.padding(24.dp),
    verticalArrangement = Arrangement.spacedBy(16.dp)
  ) {
    // background BEFORE padding -> color fills the whole box,
    // content (the Text) is inset by the padding. "padding" feel.
    Text(
      text = "background then padding",
      modifier = Modifier
        .background(Color(0xFFFF6B6B), RoundedCornerShape(8.dp))
        .padding(16.dp)
    )

    // padding BEFORE background -> padding reserves a transparent gap
    // first, background only fills the smaller inner area. "margin" feel.
    Text(
      text = "padding then background",
      modifier = Modifier
        .padding(16.dp)
        .background(Color(0xFFFF6B6B), RoundedCornerShape(8.dp))
    )

    // Accessible tap target: clickable first so the padding is tappable too.
    Text(
      text = "clickable then padding",
      modifier = Modifier
        .clip(RoundedCornerShape(8.dp))
        .clickable { /* handle tap over the full padded area */ }
        .background(Color(0xFF4ECDC4))
        .padding(16.dp)
    )
  }
}

@Composable
fun DensityDemo() {
  // Type-safe Dp arithmetic — units are checked by the compiler.
  val basePadding = 16.dp
  val gap = basePadding / 2          // 8.dp
  val cardHeight = basePadding * 4   // 64.dp

  // Read the device Density to see how dp maps to real pixels.
  val density = LocalDensity.current
  val paddingPx = with(density) { basePadding.toPx() }  // e.g. 48f at density 3.0

  Column(
    modifier = Modifier
      .padding(basePadding)                 // Dp -> px at draw time
      .border(Dp.Hairline, Color.Gray),     // thinnest crisp 1px line
    verticalArrangement = Arrangement.spacedBy(gap)
  ) {
    Box(Modifier.size(cardHeight).background(Color(0xFF6C8EBF)))

    // Text uses sp: scales with density AND the user's font setting.
    Text(
      text = "16.dp = ${"%.0f".format(paddingPx)} px at " +
        "density ${density.density}, fontScale ${density.fontScale}",
      fontSize = 16.sp,
      lineHeight = 22.sp
    )

    // Responsive decision driven by a Dp comparison.
    val label = if (cardHeight > 48.dp) "comfortable" else "compact"
    Text(label, fontSize = 14.sp)
  }
}

@Composable
fun SizingShowcase() {
  Column(
    modifier = Modifier
      .fillMaxWidth()          // expand to parent's max width
      .padding(16.dp),
    verticalArrangement = Arrangement.spacedBy(12.dp)
  ) {
    // Fixed: both axes pinned; still clamped by parent constraints.
    Box(
      Modifier
        .size(120.dp, 48.dp)
        .background(Color(0xFF26A69A))
    )

    // Fractional fill: 60% of the Column's available width.
    Box(
      Modifier
        .fillMaxWidth(0.6f)
        .height(40.dp)
        .background(Color(0xFFFF7043))
    )

    // Ranged: free to size between 80.dp and 200.dp wide.
    Text(
      text = "I grow with my text, within bounds",
      modifier = Modifier
        .widthIn(min = 80.dp, max = 200.dp)
        .background(Color(0xFF5C6BC0))
        .padding(8.dp)
    )

    // requiredSize ignores parent constraints and may overflow.
    Box(
      Modifier
        .fillMaxWidth()
        .height(60.dp)
        .background(Color(0xFFB0BEC5)),
      contentAlignment = Alignment.Center
    ) {
      Box(
        Modifier
          .requiredSize(360.dp, 40.dp) // wider than the parent on purpose
          .background(Color(0xFFFFCA28))
      )
    }

    // matchParentSize: background stretches to the Box's other children.
    Box {
      Box(Modifier.matchParentSize().background(Color(0xFFE0E0E0)))
      Text(
        "Sized by me; background matches",
        modifier = Modifier.padding(24.dp)
      )
    }
  }
}

@Composable
fun AspectRatioDemo() {
  // Width is fixed at 200.dp; height is derived as 200 / ratio.
  Box(
    modifier = Modifier
      .width(200.dp)          // bound one dimension first
      .aspectRatio(16f / 9f)  // height becomes 200 / (16/9) = 112.5.dp
      .clip(RoundedCornerShape(12.dp))
      .background(Color(0xFF26A69A)),
    contentAlignment = Alignment.Center
  ) {
    Text("16:9", color = Color.White)
  }

  // Height-bounded case: derive width from a fixed height.
  Box(
    modifier = Modifier
      .height(120.dp)
      .aspectRatio(1f, matchHeightConstraintsFirst = true) // width = 120.dp
      .background(Color(0xFFFF7043))
  )
}

@Composable
fun PaddingShowcase() {
  // padding(all): same inset on all four sides, drawn INSIDE the background
  Box(
    Modifier
      .background(Color(0xFF26A69A), RoundedCornerShape(12.dp))
      .padding(16.dp) // background first, then inset -> teal shows around content
  ) {
    Text("Inset 16dp on every side")
  }

  Spacer(Modifier.height(12.dp)) // "margin" between the two boxes

  // Per-side, RTL-aware padding via start/end (mirrors in RTL locales)
  Text(
    "More breathing room at the start",
    Modifier
      .background(Color(0xFFFF7043), RoundedCornerShape(8.dp))
      .padding(start = 24.dp, top = 8.dp, end = 8.dp, bottom = 8.dp)
  )

  // Scrollables take contentPadding (PaddingValues), NOT Modifier.padding,
  // so the first/last items aren't clipped by the scroll viewport.
  LazyColumn(
    contentPadding = PaddingValues(horizontal = 16.dp, vertical = 12.dp),
    verticalArrangement = Arrangement.spacedBy(8.dp) // gap between items
  ) {
    items(20) { i -> Text("Row $i") }
  }
}

@Composable
fun SpacingDemo() {
  // 1) spacedBy: even gaps between every child, no edge padding
  Column(
    modifier = Modifier
      .fillMaxWidth()
      .padding(16.dp),               // outer margin (independent of gaps)
    verticalArrangement = Arrangement.spacedBy(12.dp)
  ) {
    Text("First")
    Text("Second")
    Text("Third")                    // 3 items -> 2 gaps of 12.dp
  }

  // 2) Fixed one-off gap with a Spacer
  Column {
    Text("Title")
    Spacer(Modifier.height(8.dp))    // height -> vertical gap in a Column
    Text("Subtitle")
  }

  // 3) Weighted Spacer pushes items to opposite ends
  Row(
    modifier = Modifier.fillMaxWidth(),
    verticalAlignment = Alignment.CenterVertically
  ) {
    Text("Inbox")
    Spacer(Modifier.weight(1f))      // absorbs all leftover width
    Icon(Icons.Default.Settings, contentDescription = "Settings")
  }
}

@Composable
fun OffsetExamples() {
  // 1. Static nudge: moves visually, reserves no extra space.
  //    The sibling below stays where it would have been.
  Column {
    Text(
      text = "Nudged right & up",
      modifier = Modifier.offset(x = 16.dp, y = (-4).dp)
    )
    Text(text = "I do NOT move to follow the offset above")
  }

  // 2. Overlapping badge inside a Box.
  Box {
    Icon(Icons.Default.Notifications, contentDescription = "Alerts")
    Box(
      modifier = Modifier
        .offset(x = 8.dp, y = (-8).dp)   // spill outside the icon's top-end corner
        .size(10.dp)
        .clip(CircleShape)
        .background(Color.Red)
    )
  }

  // 3. Performant animated offset: lambda overload reads state in the
  //    layout phase (pixels, not dp), skipping recomposition each frame.
  var toggled by remember { mutableStateOf(false) }
  val slide by animateDpAsState(
    targetValue = if (toggled) 120.dp else 0.dp,
    label = "slide"
  )
  Box(
    modifier = Modifier
      .offset { IntOffset(x = slide.roundToPx(), y = 0) }
      .size(48.dp)
      .background(MaterialTheme.colorScheme.primary)
      .clickable { toggled = !toggled }
  )

  // 4. absoluteOffset ignores RTL: +x is always physical-right.
  Text(
    text = "Always shifts right, even in RTL",
    modifier = Modifier.absoluteOffset(x = 12.dp)
  )
}

