fun Modifier.firstBaselineToTop(distance: Dp) = layout { measurable, constraints ->
  // Measure once.
  val placeable = measurable.measure(constraints)
  val firstBaseline = placeable[FirstBaseline]
  check(firstBaseline != AlignmentLine.Unspecified)

  val y = distance.roundToPx() - firstBaseline
  val height = max(placeable.height + y, constraints.minHeight)
    .coerceAtMost(constraints.maxHeight)

  layout(width = placeable.width, height = height) {
    // A measured child is invisible until it is placed.
    placeable.placeRelative(x = 0, y = y)
  }
}

@Composable
fun BasicColumnByHand(
  modifier: Modifier = Modifier,
  content: @Composable () -> Unit
) {
  Layout(content = content, modifier = modifier) { measurables, constraints ->
    val placeables = measurables.map { measurable ->
      measurable.measure(constraints.copy(minWidth = 0, minHeight = 0))
    }

    val width = placeables.maxOfOrNull { it.width } ?: constraints.minWidth
    val height = placeables.sumOf { it.height }

    layout(
      width = width.coerceIn(constraints.minWidth, constraints.maxWidth),
      height = height.coerceIn(constraints.minHeight, constraints.maxHeight)
    ) {
      var y = 0
      placeables.forEach { placeable ->
        placeable.placeRelative(x = 0, y = y)
        y += placeable.height
      }
    }
  }
}

@Composable
