@Composable
fun InlineConstraintProfile(modifier: Modifier = Modifier) {
  ConstraintLayout(modifier.fillMaxWidth()) {
    val (avatar, title, subtitle, action) = createRefs()

    ProfilePhoto(Modifier.constrainAs(avatar) {
      start.linkTo(parent.start, 16.dp)
      top.linkTo(parent.top, 16.dp)
    })
    Text("Ada Lovelace", Modifier.constrainAs(title) {
      start.linkTo(avatar.end, 12.dp)
      top.linkTo(avatar.top)
      end.linkTo(action.start, 12.dp)
      width = Dimension.fillToConstraints
    })
    Text("Online", Modifier.constrainAs(subtitle) {
      start.linkTo(title.start)
      top.linkTo(title.bottom, 4.dp)
    })
    Button(onClick = { }, Modifier.constrainAs(action) {
      end.linkTo(parent.end, 16.dp)
      top.linkTo(parent.top, 16.dp)
    }) { Text("Follow") }
  }
}

@Composable
fun AdaptiveConstraintProfile(modifier: Modifier = Modifier) {
  BoxWithConstraints(modifier) {
    val constraints = if (maxWidth < 600.dp) {
      compactProfileConstraints(16.dp)
    } else {
      expandedProfileConstraints(24.dp)
    }

    ConstraintLayout(constraintSet = constraints, modifier = Modifier.fillMaxWidth()) {
      ProfilePhoto(Modifier.layoutId(ProfileSlots.Photo))
      Text("Ada Lovelace", Modifier.layoutId(ProfileSlots.Title))
      Button(onClick = { }, modifier = Modifier.layoutId(ProfileSlots.Action)) {
        Text("Follow")
      }
    }
  }
}

private object ProfileSlots {
  const val Photo = "photo"
  const val Title = "title"
  const val Action = "action"
}

private fun compactProfileConstraints(margin: Dp) = ConstraintSet {
  val photo = createRefFor(ProfileSlots.Photo)
  val title = createRefFor(ProfileSlots.Title)
  val action = createRefFor(ProfileSlots.Action)

  constrain(photo) {
    start.linkTo(parent.start, margin)
    top.linkTo(parent.top, margin)
  }
  constrain(title) {
    start.linkTo(photo.end, 12.dp)
    top.linkTo(photo.top)
    end.linkTo(action.start, 12.dp)
    width = Dimension.fillToConstraints
  }
  constrain(action) {
    end.linkTo(parent.end, margin)
    top.linkTo(photo.top)
  }
}

private fun expandedProfileConstraints(margin: Dp) = ConstraintSet {
  val photo = createRefFor(ProfileSlots.Photo)
  val title = createRefFor(ProfileSlots.Title)
  val action = createRefFor(ProfileSlots.Action)
  val contentGuide = createGuidelineFromStart(0.32f)

  constrain(photo) {
    start.linkTo(parent.start, margin)
    top.linkTo(parent.top, margin)
  }
  constrain(title) {
    start.linkTo(contentGuide, margin)
    top.linkTo(photo.top)
  }
  constrain(action) {
    start.linkTo(title.start)
    top.linkTo(title.bottom, 16.dp)
  }
}

