@Composable
fun ArticleFeed(
  articles: List<ArticleUi>,
  onImpression: (articleId: String) -> Unit,
  onGeometrySample: (VisibleGeometry) -> Unit,
  modifier: Modifier = Modifier
) {
  LazyColumn(modifier) {
    items(
      items = articles,
      key = { article -> article.id },
      contentType = { "article-card" }
    ) { article ->
      ImpressionArticleCard(
        article = article,
        onImpression = onImpression,
        onGeometrySample = onGeometrySample,
        modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp)
      )
    }
  }
}

@Composable
fun ImpressionArticleCard(
  article: ArticleUi,
  onImpression: (articleId: String) -> Unit,
  onGeometrySample: (VisibleGeometry) -> Unit,
  modifier: Modifier = Modifier
) {
  var impressionLogged by rememberSaveable(article.id) { mutableStateOf(false) }

  Card(
    modifier = modifier
      .fillMaxWidth()
      .onVisibilityChanged(
        minFractionVisible = 0.5f,
        minDurationMs = 1000
      ) { visible ->
        if (visible && !impressionLogged) {
          impressionLogged = true
          onImpression(article.id)
        }
      }
      .onLayoutRectChanged(
        throttleMillis = 250,
        debounceMillis = 250
      ) { bounds ->
        onGeometrySample(
          VisibleGeometry(
            id = article.id,
            fractionVisible = bounds.fractionVisibleInWindow(),
            boundsInWindow = bounds.boundsInWindow
          )
        )
      }
  ) {
    Column(Modifier.padding(16.dp)) {
      Text(article.title, style = MaterialTheme.typography.titleMedium)
      Text(article.summary, style = MaterialTheme.typography.bodyMedium)
    }
  }
}

data class ArticleUi(
  val id: String,
  val title: String,
  val summary: String
)

data class VisibleGeometry(
  val id: String,
  val fractionVisible: Float,
  val boundsInWindow: IntRect
)

@Composable
fun ArrangementShowcase() {
  // A Row that fills its width has free space to distribute.
  Row(
    modifier = Modifier
      .fillMaxWidth()
      .padding(16.dp),
    horizontalArrangement = Arrangement.SpaceBetween,
    verticalAlignment = Alignment.CenterVertically
  ) {
    Text("Start")
    Text("Middle")
    Text("End")
  }

  // Fixed, uniform spacing between items — the idiomatic gap.
  Column(
    modifier = Modifier.fillMaxWidth(),
    verticalArrangement = Arrangement.spacedBy(8.dp)
  ) {
    repeat(3) { i -> Text("Item $i") }
  }

  // Space the block AND anchor it to the end of the axis.
  Row(
    modifier = Modifier.fillMaxWidth(),
    horizontalArrangement = Arrangement.spacedBy(12.dp, Alignment.End)
  ) {
    Text("A"); Text("B")
  }
}

// 1) Box: 2D alignment for the whole container, overridable per child
Box(
  modifier = Modifier
    .size(200.dp)
    .background(Color(0xFFE0E0E0)),
  contentAlignment = Alignment.Center // default would be TopStart
) {
  Text("centered")
  // This child overrides the container default just for itself:
  Text(
    "pinned",
    modifier = Modifier.align(Alignment.BottomEnd)
  )
}

// 2) Column: horizontalAlignment is the CROSS axis (default = Start)
Column(
  modifier = Modifier.fillMaxWidth(),
  horizontalAlignment = Alignment.CenterHorizontally
) {
  Text("title")
  Text(
    "left-pinned",
    modifier = Modifier.align(Alignment.Start) // per-child override
  )
}

// 3) Row: verticalAlignment is the CROSS axis (default = Top)
Row(verticalAlignment = Alignment.CenterVertically) {
  Box(Modifier.size(40.dp).background(Color(0xFF80CBC4)))
  Text("vertically centered next to the box")
}

// 4) Baseline alignment: line up letters, not boxes
Row {
  Text("Big", fontSize = 32.sp, modifier = Modifier.alignByBaseline())
  Text("small", fontSize = 14.sp, modifier = Modifier.alignByBaseline())
}

@Composable
fun WeightDemo() {
  Row(
    modifier = Modifier
      .fillMaxWidth()
      .height(56.dp),
    horizontalArrangement = Arrangement.spacedBy(8.dp),
    verticalAlignment = Alignment.CenterVertically
  ) {
    // No weight: measured first, takes its intrinsic width.
    Icon(Icons.Default.Star, contentDescription = null)

    // weight(1f): takes one share of the LEFTOVER space.
    Text(
      text = "Title",
      modifier = Modifier
        .weight(1f)
        .background(Color(0xFFE3F2FD))
    )

    // weight(2f): twice the share of the same leftover space.
    // fill = false -> it may be narrower than its slot if the
    // text wraps short; the slot is a maximum, not a target.
    Text(
      text = "Subtitle that can grow",
      modifier = Modifier
        .weight(2f, fill = false)
        .background(Color(0xFFFFF3E0))
    )
  }
}

