@Composable
fun GraphicsPatterns(progress: Float, highlighted: Boolean) {
  Text(
    text = "Draw behind content",
    modifier = Modifier
      .drawBehind {
        drawRoundRect(
          color = Color(0xFFE0F2FE),
          cornerRadius = androidx.compose.ui.geometry.CornerRadius(12.dp.toPx())
        )
      }
      .padding(horizontal = 12.dp, vertical = 8.dp)
  )

  Box(
    Modifier
      .fillMaxWidth()
      .height(96.dp)
      .drawWithCache {
        val gradient = Brush.horizontalGradient(
          listOf(Color(0xFF14B8A6), Color(0xFF6366F1))
        )
        onDrawBehind {
          drawRect(gradient)
          drawRect(Color.Black.copy(alpha = 0.16f))
        }
      }
  )

  Text(
    text = "Overlay",
    modifier = Modifier.drawWithContent {
      drawContent() // omit this only when replacing content intentionally
      drawRect(Color.Yellow.copy(alpha = 0.22f), size = size)
    }
  )

  Canvas(Modifier.fillMaxWidth().height(72.dp)) {
    val barWidth = size.width * progress.coerceIn(0f, 1f)
    drawRect(Color(0xFFE5E7EB))
    drawRect(Color(0xFF0F766E), size = size.copy(width = barWidth))
  }

  Box(
    Modifier
      .graphicsLayer {
        rotationZ = if (highlighted) -3f else 0f
        scaleX = if (highlighted) 1.04f else 1f
        scaleY = if (highlighted) 1.04f else 1f
        shadowElevation = if (highlighted) 16.dp.toPx() else 0f
        clip = false
      }
      .background(MaterialTheme.colorScheme.primaryContainer)
      .padding(16.dp)
  ) {
    Text("Layer transform does not change measured size")
  }
}

