@Composable
fun PhotoGridRoute(
  viewModel: PhotoGridViewModel,
  analytics: Analytics,
  modifier: Modifier = Modifier
) {
  val photos = viewModel.photos.collectAsLazyPagingItems()
  val gridState = rememberLazyGridState()

  LaunchedEffect(gridState) {
    snapshotFlow { gridState.firstVisibleItemIndex }
      .map { index -> index > 0 }
      .distinctUntilChanged()
      .filter { it }
      .collect { analytics.scrolledPastFirstPhoto() }
  }

  PhotoGrid(
    photos = photos,
    gridState = gridState,
    modifier = modifier.fillMaxSize()
  )
}

@Composable
fun PhotoGrid(
  photos: LazyPagingItems<PhotoUi>,
  gridState: LazyGridState,
  modifier: Modifier = Modifier
) {
  LazyVerticalGrid(
    columns = GridCells.Adaptive(minSize = 160.dp),
    state = gridState,
    modifier = modifier,
    contentPadding = PaddingValues(16.dp),
    verticalArrangement = Arrangement.spacedBy(12.dp),
    horizontalArrangement = Arrangement.spacedBy(12.dp)
  ) {
    item(
      span = { GridItemSpan(maxLineSpan) },
      contentType = "filters"
    ) {
      FlowRow(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.spacedBy(8.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
      ) {
        PhotoFilter.entries.forEach { filter ->
          AssistChip(onClick = { }, label = { Text(filter.label) })
        }
      }
    }

    items(
      count = photos.itemCount,
      key = photos.itemKey { photo -> photo.id },
      contentType = photos.itemContentType { "photo" }
    ) { index ->
      val photo = photos[index]
      if (photo == null) {
        PhotoPlaceholder(Modifier.animateItem())
      } else {
        PhotoCard(photo = photo, modifier = Modifier.animateItem())
      }
    }

    when (val append = photos.loadState.append) {
      is LoadState.Loading -> item(span = { GridItemSpan(maxLineSpan) }, contentType = "append-loading") { LoadingRow() }
      is LoadState.Error -> item(span = { GridItemSpan(maxLineSpan) }, contentType = "append-error") { RetryRow(onRetry = photos::retry) }
      else -> Unit
    }
  }
}

