@Immutable
data class BrandTokens(
  val warning: Color,
  val onWarning: Color,
  val avatarContainer: Color
)

private val LocalBrandTokens = staticCompositionLocalOf {
  BrandTokens(
    warning = Color.Unspecified,
    onWarning = Color.Unspecified,
    avatarContainer = Color.Unspecified
  )
}

object BrandTheme {
  val tokens: BrandTokens
    @Composable get() = LocalBrandTokens.current
}

@Composable
fun ComposeMasterTheme(
  darkTheme: Boolean = isSystemInDarkTheme(),
  dynamicColor: Boolean = true,
  content: @Composable () -> Unit
) {
  val context = LocalContext.current
  val colors = when {
    dynamicColor && Build.VERSION.SDK_INT >= Build.VERSION_CODES.S ->
      if (darkTheme) dynamicDarkColorScheme(context) else dynamicLightColorScheme(context)
    darkTheme -> DarkColors
    else -> LightColors
  }
  val brandTokens = if (darkTheme) {
    BrandTokens(
      warning = Color(0xFFF2D79A),
      onWarning = Color(0xFF2A2310),
      avatarContainer = Color(0xFF134E4A)
    )
  } else {
    BrandTokens(
      warning = Color(0xFF7A5A12),
      onWarning = Color(0xFFFFF6E5),
      avatarContainer = Color(0xFFCCFBF1)
    )
  }

  CompositionLocalProvider(LocalBrandTokens provides brandTokens) {
    MaterialTheme(
      colorScheme = colors,
      typography = MaterialTheme.typography,
      shapes = MaterialTheme.shapes,
      content = content
    )
  }
}

