@Composable
fun ButtonShowcase(
  enabled: Boolean,
  onSave: () -> Unit,
  onCancel: () -> Unit,
) {
  // Highest emphasis: the single primary action on the screen.
  Button(onClick = onSave, enabled = enabled) {
    Text("Save")
  }

  // Filled tonal: an important, but not primary, action.
  FilledTonalButton(onClick = onSave) {
    Text("Save draft")
  }

  // Elevated: a tonal button with a shadow for busy surfaces.
  ElevatedButton(onClick = onSave) {
    Text("Export")
  }

  // Outlined: a secondary action. Note: leading icon + Material spacing.
  OutlinedButton(
    onClick = onSave,
    contentPadding = ButtonDefaults.ButtonWithIconContentPadding,
  ) {
    Icon(
      imageVector = Icons.Filled.Add,
      contentDescription = null, // decorative; label conveys the action
    )
    Spacer(Modifier.width(ButtonDefaults.IconSpacing))
    Text("Add item")
  }

  // Lowest emphasis: dismissals, inline actions.
  TextButton(onClick = onCancel) {
    Text("Cancel")
  }
}

