@Composable
fun SettingsControls() {
  // State lives HERE and flows down into each stateless control.
  var notify by remember { mutableStateOf(true) }
  var agreed by remember { mutableStateOf(false) }
  var plan by remember { mutableStateOf("Free") }
  var volume by remember { mutableStateOf(0.4f) }

  Column {
    // Switch: checked + onCheckedChange. It does NOT flip itself.
    Row(verticalAlignment = Alignment.CenterVertically) {
      Switch(checked = notify, onCheckedChange = { notify = it })
      Text("Notifications", Modifier.padding(start = 8.dp))
    }

    // Checkbox: same shape as Switch.
    Row(verticalAlignment = Alignment.CenterVertically) {
      Checkbox(checked = agreed, onCheckedChange = { agreed = it })
      Text("I agree", Modifier.padding(start = 8.dp))
    }

    // RadioButton GROUP: you build it. Note selected + onClick (not onCheckedChange),
    // and selectableGroup() on the parent for correct accessibility.
    Column(Modifier.selectableGroup()) {
      listOf("Free", "Pro", "Team").forEach { option ->
        Row(verticalAlignment = Alignment.CenterVertically) {
          RadioButton(
            selected = (option == plan),   // exactly one is true
            onClick = { plan = option },
          )
          Text(option, Modifier.padding(start = 8.dp))
        }
      }
    }

    // Slider: value: Float + onValueChange. steps = 4 over 0f..5f => 6 stops.
    Text("Volume: ${(volume * 100).toInt()}%")
    Slider(
      value = volume,
      onValueChange = { volume = it },     // cheap, fires per frame
      valueRange = 0f..1f,
      steps = 0,                            // 0 = continuous
      onValueChangeFinished = { /* commit on release */ },
    )
  }
}

