@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SearchAndFilterPanel(
  suggestions: List<String>,
  filters: List<String>,
  selectedFilters: Set<String>,
  selectedSortIndex: Int,
  onSearch: (String) -> Unit,
  onSuggestionClick: (String) -> Unit,
  onFilterToggle: (String) -> Unit,
  onSortSelected: (Int) -> Unit,
  onDateSelected: (Long) -> Unit,
  modifier: Modifier = Modifier
) {
  var query by rememberSaveable { mutableStateOf("") }
  var expanded by rememberSaveable { mutableStateOf(false) }
  var showDatePicker by rememberSaveable { mutableStateOf(false) }
  val datePickerState = rememberDatePickerState()
  val sortOptions = listOf("Best", "Newest", "Saved")

  Column(modifier, verticalArrangement = Arrangement.spacedBy(12.dp)) {
    SearchBar(
      modifier = Modifier.fillMaxWidth(),
      inputField = {
        SearchBarDefaults.InputField(
          query = query,
          onQueryChange = { query = it },
          onSearch = {
            expanded = false
            onSearch(query)
          },
          expanded = expanded,
          onExpandedChange = { expanded = it },
          placeholder = { Text("Search places") },
          leadingIcon = { Icon(Icons.Default.Search, contentDescription = null) },
          trailingIcon = {
            if (query.isNotEmpty()) {
              IconButton(onClick = { query = "" }) {
                Icon(Icons.Default.Close, contentDescription = "Clear search")
              }
            }
          }
        )
      },
      expanded = expanded,
      onExpandedChange = { expanded = it }
    ) {
      LazyColumn {
        items(suggestions, key = { it }) { suggestion ->
          ListItem(
            headlineContent = { Text(suggestion) },
            modifier = Modifier.clickable {
              query = suggestion
              expanded = false
              onSuggestionClick(suggestion)
            }
          )
        }
      }
    }

    FlowRow(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
      filters.forEach { filter ->
        FilterChip(
          selected = filter in selectedFilters,
          onClick = { onFilterToggle(filter) },
          label = { Text(filter) },
          leadingIcon = if (filter in selectedFilters) {
            { Icon(Icons.Default.Check, contentDescription = null) }
          } else null
        )
      }
    }

    SingleChoiceSegmentedButtonRow {
      sortOptions.forEachIndexed { index, label ->
        SegmentedButton(
          selected = selectedSortIndex == index,
          onClick = { onSortSelected(index) },
          shape = SegmentedButtonDefaults.itemShape(index, sortOptions.size)
        ) {
          Text(label)
        }
      }
    }

    TextButton(onClick = { showDatePicker = true }) { Text("Choose date") }
  }

  if (showDatePicker) {
    DatePickerDialog(
      onDismissRequest = { showDatePicker = false },
      confirmButton = {
        TextButton(onClick = {
          datePickerState.selectedDateMillis?.let(onDateSelected)
          showDatePicker = false
        }) { Text("OK") }
      },
      dismissButton = {
        TextButton(onClick = { showDatePicker = false }) { Text("Cancel") }
      }
    ) {
      DatePicker(state = datePickerState)
    }
  }
}

