@Composable
fun SignInTextFields(
  onSubmit: (username: String, phone: String) -> Unit,
  modifier: Modifier = Modifier
) {
  val usernameState = rememberTextFieldState()
  val phoneState = rememberTextFieldState()
  val passwordState = rememberTextFieldState()
  val autofillManager = LocalAutofillManager.current

  Column(
    modifier = modifier.padding(16.dp),
    verticalArrangement = Arrangement.spacedBy(16.dp)
  ) {
    OutlinedTextField(
      state = usernameState,
      label = { Text("Username or email") },
      placeholder = { Text("ada@example.com") },
      lineLimits = TextFieldLineLimits.SingleLine,
      keyboardOptions = KeyboardOptions(
        keyboardType = KeyboardType.Email,
        imeAction = ImeAction.Next
      ),
      modifier = Modifier
        .fillMaxWidth()
        .semantics {
          contentType = ContentType.Username + ContentType.EmailAddress
        }
    )

    OutlinedTextField(
      state = phoneState,
      label = { Text("Phone") },
      lineLimits = TextFieldLineLimits.SingleLine,
      keyboardOptions = KeyboardOptions(
        keyboardType = KeyboardType.Phone,
        imeAction = ImeAction.Next
      ),
      inputTransformation = InputTransformation.maxLength(10).then(
        InputTransformation {
          if (asCharSequence().any { !it.isDigit() }) revertAllChanges()
        }
      ),
      outputTransformation = OutputTransformation {
        if (length > 0) insert(0, "(")
        if (length > 4) insert(4, ")")
        if (length > 8) insert(8, "-")
      },
      modifier = Modifier
        .fillMaxWidth()
        .semantics { contentType = ContentType.PhoneNumber }
    )

    SecureTextField(
      state = passwordState,
      label = { Text("Password") },
      textObfuscationMode = TextObfuscationMode.RevealLastTyped,
      keyboardOptions = KeyboardOptions(
        keyboardType = KeyboardType.Password,
        imeAction = ImeAction.Done
      ),
      modifier = Modifier
        .fillMaxWidth()
        .semantics { contentType = ContentType.NewPassword }
    )

    Button(
      onClick = {
        onSubmit(usernameState.text.toString(), phoneState.text.toString())
        autofillManager?.commit()
      }
    ) {
      Text("Create account")
    }
  }
}

