@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun TransientSurfacePatterns(
  unreadCount: Int,
  onDelete: () -> Unit,
  onUndoDelete: () -> Unit,
  modifier: Modifier = Modifier
) {
  val snackbarHostState = remember { SnackbarHostState() }
  val scope = rememberCoroutineScope()
  var showDeleteDialog by rememberSaveable { mutableStateOf(false) }
  var menuExpanded by remember { mutableStateOf(false) }
  var showSheet by rememberSaveable { mutableStateOf(false) }
  val sheetState = rememberModalBottomSheetState(skipPartiallyExpanded = false)

  Scaffold(
    modifier = modifier,
    snackbarHost = { SnackbarHost(snackbarHostState) }
  ) { innerPadding ->
    Column(
      Modifier.padding(innerPadding).padding(16.dp),
      verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
      BadgedBox(
        badge = {
          if (unreadCount > 0) Badge { Text(unreadCount.coerceAtMost(99).toString()) }
        }
      ) {
        Icon(Icons.Default.Mail, contentDescription = "Messages")
      }

      TooltipBox(
        positionProvider = TooltipDefaults.rememberPlainTooltipPositionProvider(),
        tooltip = { PlainTooltip { Text("Search") } },
        state = rememberTooltipState()
      ) {
        IconButton(onClick = { /* search */ }) {
          Icon(Icons.Default.Search, contentDescription = "Search")
        }
      }

      Box {
        IconButton(onClick = { menuExpanded = true }) {
          Icon(Icons.Default.MoreVert, contentDescription = "More options")
        }
        DropdownMenu(
          expanded = menuExpanded,
          onDismissRequest = { menuExpanded = false }
        ) {
          DropdownMenuItem(
            text = { Text("Delete") },
            leadingIcon = { Icon(Icons.Default.Delete, contentDescription = null) },
            onClick = {
              menuExpanded = false
              showDeleteDialog = true
            }
          )
        }
      }

      Button(onClick = { showSheet = true }) { Text("Filter") }
    }

    if (showDeleteDialog) {
      AlertDialog(
        onDismissRequest = { showDeleteDialog = false },
        title = { Text("Delete message?") },
        text = { Text("You can undo this immediately after deleting.") },
        confirmButton = {
          TextButton(onClick = {
            showDeleteDialog = false
            onDelete()
            scope.launch {
              val result = snackbarHostState.showSnackbar(
                message = "Message deleted",
                actionLabel = "Undo",
                withDismissAction = true,
                duration = SnackbarDuration.Short
              )
              if (result == SnackbarResult.ActionPerformed) onUndoDelete()
            }
          }) { Text("Delete") }
        },
        dismissButton = {
          TextButton(onClick = { showDeleteDialog = false }) { Text("Cancel") }
        }
      )
    }

    if (showSheet) {
      ModalBottomSheet(
        sheetState = sheetState,
        onDismissRequest = { showSheet = false }
      ) {
        Text("Sort and filter", Modifier.padding(24.dp))
        Button(onClick = {
          scope.launch { sheetState.hide() }.invokeOnCompletion {
            if (!sheetState.isVisible) showSheet = false
          }
        }) { Text("Apply") }
      }
    }
  }
}

