@Immutable
data class AppDestination(
  val route: String,
  val label: String,
  val icon: ImageVector
)

private val MainDestinations = listOf(
  AppDestination("home", "Home", Icons.Default.Home),
  AppDestination("inbox", "Inbox", Icons.Default.Inbox),
  AppDestination("saved", "Saved", Icons.Default.Bookmark)
)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AdaptiveNavigationShell(
  currentDestination: AppDestination,
  onDestinationClick: (AppDestination) -> Unit,
  onOpenDrawer: () -> Unit,
  modifier: Modifier = Modifier,
  content: @Composable (PaddingValues) -> Unit
) {
  val windowSizeClass = currentWindowAdaptiveInfo(
    supportLargeAndXLargeWidth = true
  ).windowSizeClass
  val useRail = windowSizeClass.isWidthAtLeastBreakpoint(
    WindowSizeClass.WIDTH_DP_MEDIUM_LOWER_BOUND
  )

  if (useRail) {
    Row(modifier.fillMaxSize()) {
      NavigationRail {
        MainDestinations.forEach { destination ->
          NavigationRailItem(
            selected = currentDestination.route == destination.route,
            onClick = { onDestinationClick(destination) },
            icon = { Icon(destination.icon, contentDescription = destination.label) },
            label = { Text(destination.label) }
          )
        }
      }

      Scaffold(
        modifier = Modifier.weight(1f),
        topBar = {
          TopAppBar(
            title = { Text(currentDestination.label) },
            navigationIcon = {
              IconButton(onClick = onOpenDrawer) {
                Icon(Icons.Default.Menu, contentDescription = "Open navigation drawer")
              }
            }
          )
        }
      ) { innerPadding ->
        content(innerPadding)
      }
    }
  } else {
    Scaffold(
      modifier = modifier,
      topBar = {
        TopAppBar(
          title = { Text(currentDestination.label) },
          navigationIcon = {
            IconButton(onClick = onOpenDrawer) {
              Icon(Icons.Default.Menu, contentDescription = "Open navigation drawer")
            }
          }
        )
      },
      bottomBar = {
        NavigationBar {
          MainDestinations.forEach { destination ->
            NavigationBarItem(
              selected = currentDestination.route == destination.route,
              onClick = { onDestinationClick(destination) },
              icon = { Icon(destination.icon, contentDescription = destination.label) },
              label = { Text(destination.label) }
            )
          }
        }
      }
    ) { innerPadding ->
      content(innerPadding)
    }
  }
}

