@Composable
fun DismissScrim(
  onClose: () -> Unit,
  modifier: Modifier = Modifier
) {
  val latestOnClose = rememberUpdatedState(onClose)
  val closeLabel = "Close"

  Box(
    modifier
      // Raw pointer input is appropriate here because a scrim should not ripple
      // or behave like an ordinary focusable button.
      .pointerInput(Unit) {
        detectTapGestures { latestOnClose.value() }
      }
      // Raw pointer input does not add this contract for you.
      .semantics(mergeDescendants = true) {
        contentDescription = closeLabel
        onClick(label = closeLabel) {
          latestOnClose.value()
          true
        }
      }
      .onKeyEvent { event ->
        if (event.key == Key.Escape) {
          latestOnClose.value()
          true
        } else {
          false
        }
      }
      .background(Color.Black.copy(alpha = 0.55f))
  )
}

