@Composable
fun SearchPane(
  filters: List<String>,
  selectedFilter: String,
  onFilterSelected: (String) -> Unit,
  onSearch: (String) -> Unit,
  modifier: Modifier = Modifier
) {
  var query by remember { mutableStateOf("") }
  var queryFocused by remember { mutableStateOf(false) }
  val focusManager = LocalFocusManager.current
  val (queryRef, firstFilterRef) = remember { FocusRequester.createRefs() }

  Column(
    modifier = modifier
      // Parent-first shortcut: descendants still get the event when we return false.
      .onPreviewKeyEvent { event ->
        if (event.type == KeyEventType.KeyUp && event.isCtrlPressed && event.key == Key.K) {
          queryRef.requestFocus()
          true
        } else {
          false
        }
      }
      .padding(16.dp),
    verticalArrangement = Arrangement.spacedBy(12.dp)
  ) {
    OutlinedTextField(
      value = query,
      onValueChange = { query = it },
      label = { Text("Search") },
      supportingText = {
        if (queryFocused) Text("Press Ctrl+K to return here from anywhere in this panel.")
      },
      singleLine = true,
      keyboardOptions = KeyboardOptions(imeAction = ImeAction.Search),
      keyboardActions = KeyboardActions(onSearch = {
        onSearch(query)
        focusManager.clearFocus()
      }),
      modifier = Modifier
        .focusRequester(queryRef)
        .focusProperties { next = firstFilterRef }
        .onFocusChanged { queryFocused = it.isFocused }
        .fillMaxWidth()
    )

    Row(
      modifier = Modifier.focusGroup(),
      horizontalArrangement = Arrangement.spacedBy(8.dp)
    ) {
      filters.forEachIndexed { index, filter ->
        val chipModifier =
          if (index == 0) {
            Modifier
              .focusRequester(firstFilterRef)
              .focusProperties { previous = queryRef }
          } else {
            Modifier
          }

        FilterChip(
          selected = filter == selectedFilter,
          onClick = { onFilterSelected(filter) },
          label = { Text(filter) },
          modifier = chipModifier
        )
      }
    }

    Button(onClick = { firstFilterRef.requestFocus() }) {
      Text("Review filters")
    }
  }
}

@Composable
fun ShortcutTarget(
  onSave: () -> Unit,
  modifier: Modifier = Modifier
) {
  Column(
    modifier
      // A custom key target must be reachable by focus.
      .onPreviewKeyEvent { event ->
        if (event.type == KeyEventType.KeyUp && event.isCtrlPressed && event.key == Key.S) {
          onSave()
          true
        } else {
          false
        }
      }
      .focusable()
  ) {
    Text("Press Ctrl+S while this panel is focused.")
  }
}

// A Compose UI is a TREE. Containers expose a trailing { } content slot;
// you nest children inside, as deep as needed. This screen's tree is:
//   Card > Column > [ Row[Icon, Text], Text, HorizontalDivider, Row[Button, Button] ]
// Read the indentation as depth: deeper indent == deeper in the tree.
@Composable
fun ProfileCard(modifier: Modifier = Modifier) {
  Card(modifier = modifier.fillMaxWidth()) {        // root of this subtree
    Column(                                          // a Column nested in the Card
      modifier = Modifier.padding(16.dp),
      verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
      Row(                                           // a Row nested in the Column
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(8.dp)
      ) {
        Icon(                                        // leaf — no { } of its own
          Icons.Default.Person,
          contentDescription = null,
          tint = MaterialTheme.colorScheme.primary
        )
        Text("Ada Lovelace", style = MaterialTheme.typography.titleMedium)
      }
      Text(                                          // leaf nested directly in the Column
        "Mathematician · 1815",
        color = MaterialTheme.colorScheme.onSurfaceVariant
      )
      HorizontalDivider()
      Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {  // another nested Row
        Button(onClick = {}) { Text("Follow") }      // Button's own { } content slot
        OutlinedButton(onClick = {}) { Text("Message") }
      }
    }
  }
}

// Extraction doesn't change the tree — it names a subtree so you can reuse it.
@Composable
fun ProfileList() {
  Column(
    modifier = Modifier
      .fillMaxSize()                 // the root fills the screen, so children have real space
      .verticalScroll(rememberScrollState())
      .padding(16.dp),
    verticalArrangement = Arrangement.spacedBy(12.dp)
  ) {
    ProfileCard()                    // each call drops the same subtree in again
    ProfileCard()
    ProfileCard()
  }
}

