@OptIn(ExperimentalMaterial3Api::class, ExperimentalLayoutApi::class)
@Composable
fun ConversationRoute(
  messages: List<Message> = emptyList(),
  modifier: Modifier = Modifier
) {
  Scaffold(
    modifier = modifier.fillMaxSize(),
    topBar = { TopAppBar(title = { Text("Messages") }) }
  ) { innerPadding ->
    LazyColumn(
      modifier = Modifier
        .fillMaxSize()
        // Scaffold provides this. You still have to apply it.
        .padding(innerPadding)
        // Tell descendants that Scaffold padding has already been handled.
        .consumeWindowInsets(innerPadding)
        // Move the list when the keyboard appears.
        .imePadding()
        .imeNestedScroll(),
      contentPadding = PaddingValues(horizontal = 16.dp, vertical = 12.dp),
      verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
      items(messages, key = { it.id }) { message ->
        MessageRow(message)
      }

      // Let the final item clear the navigation bar during edge-to-edge.
      item {
        Spacer(Modifier.windowInsetsBottomHeight(WindowInsets.systemBars))
      }
    }
  }
}

// Material 3 top bars, bottom bars, navigation bars, rails, drawers, and sheets
// handle the insets they own. Custom content still needs one deliberate owner
// for each edge: Scaffold innerPadding, a WindowInsets modifier, or a spacer.

