@Composable
fun AdaptiveInboxRoute(
  articles: List<ArticleSummary>,
  modifier: Modifier = Modifier
) {
  val adaptiveInfo = currentWindowAdaptiveInfo()
  val windowSizeClass = adaptiveInfo.windowSizeClass
  val navigator = rememberListDetailPaneScaffoldNavigator<ArticleKey>()
  val scope = rememberCoroutineScope()

  Scaffold(modifier = modifier.fillMaxSize()) { innerPadding ->
    NavigableListDetailPaneScaffold(
      modifier = Modifier.padding(innerPadding),
      navigator = navigator,
      listPane = {
        AnimatedPane {
          ArticleList(
            articles = articles,
            selectedId = navigator.currentDestination?.contentKey?.id,
            onArticleClick = { article ->
              scope.launch {
                navigator.navigateTo(
                  pane = ListDetailPaneScaffoldRole.Detail,
                  contentKey = ArticleKey(article.id)
                )
              }
            }
          )
        }
      },
      detailPane = {
        AnimatedPane {
          val selected = navigator.currentDestination?.contentKey
          ArticleDetail(articleId = selected?.id)
        }
      }
    )
  }

  // Keep the window size class at the shell layer. Inner rows receive
  // selectedId, callbacks, and modifiers rather than querying display size.
}

