@Composable
fun ProfileRow(
  name: String,
  subtitle: String,
  checked: Boolean,
  onCheckedChange: (Boolean) -> Unit,
  modifier: Modifier = Modifier
) {
  Row(
    modifier = modifier
      .fillMaxWidth()
      .padding(horizontal = 16.dp, vertical = 8.dp),
    verticalAlignment = Alignment.CenterVertically,
    horizontalArrangement = Arrangement.spacedBy(12.dp)
  ) {
    // Circular avatar: size -> clip -> background (order matters)
    Box(
      modifier = Modifier
        .size(40.dp)
        .clip(CircleShape)
        .background(MaterialTheme.colorScheme.primaryContainer),
      contentAlignment = Alignment.Center
    ) {
      Text(
        text = name.take(1),
        style = MaterialTheme.typography.titleMedium,
        color = MaterialTheme.colorScheme.onPrimaryContainer
      )
    }

    // Flexible text column takes leftover space, pushing the control to the end
    Column(modifier = Modifier.weight(1f)) {
      Text(
        text = name,
        style = MaterialTheme.typography.titleMedium,
        maxLines = 1,
        overflow = TextOverflow.Ellipsis
      )
      Text(
        text = subtitle,
        style = MaterialTheme.typography.bodyMedium,
        color = MaterialTheme.colorScheme.onSurfaceVariant,
        maxLines = 1,
        overflow = TextOverflow.Ellipsis
      )
    }

    // Trailing control sits at the end
    Switch(checked = checked, onCheckedChange = onCheckedChange)
  }
}

@Composable
fun SearchRoute(viewModel: SearchViewModel = viewModel()) {
  val uiState by viewModel.uiState.collectAsStateWithLifecycle()
  SearchScreen(
    query = uiState.query,
    results = uiState.results,
    onQueryChange = viewModel::onQueryChange
  )
}

@Composable
fun SearchScreen(
  query: String,
  results: List<String>,
  onQueryChange: (String) -> Unit,
  modifier: Modifier = Modifier
) {
  var selectedTab by rememberSaveable { mutableIntStateOf(0) }

  Column(modifier.padding(16.dp)) {
    TextField(
      value = query,
      onValueChange = onQueryChange,
      singleLine = true,
      label = { Text("Search") },
      modifier = Modifier.fillMaxWidth()
    )

    TabRow(selectedTabIndex = selectedTab) {
      listOf("All", "Saved").forEachIndexed { index, label ->
        Tab(
          selected = selectedTab == index,
          onClick = { selectedTab = index },
          text = { Text(label) }
        )
      }
    }

    LazyColumn {
      items(results) { result -> Text(result) }
    }
  }
}

class SearchViewModel(
  private val savedStateHandle: SavedStateHandle
) : ViewModel() {
  private val query = savedStateHandle.getStateFlow("query", "")

  val uiState: StateFlow<SearchUiState> = query
    .map { q -> SearchUiState(query = q, results = searchRepository.search(q)) }
    .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), SearchUiState())

  fun onQueryChange(value: String) {
    savedStateHandle["query"] = value
  }
}

@Composable
fun ArticleScreen(
  articleId: String,
  onTimeout: () -> Unit,
  modifier: Modifier = Modifier
) {
  val latestOnTimeout by rememberUpdatedState(onTimeout)
  val listState = rememberLazyListState()

  // Restart the load only when the article identity changes.
  LaunchedEffect(articleId) {
    analytics.logScreen("article", articleId)
    repository.refreshArticle(articleId)
  }

  // Keep a platform listener registered only while this screen is present.
  DisposableEffect(articleId) {
    val listener = ArticleListener(articleId)
    articleBus.addListener(listener)
    onDispose { articleBus.removeListener(listener) }
  }

  // Long-running effect sees the latest callback without restarting the timer.
  LaunchedEffect(Unit) {
    delay(30_000)
    latestOnTimeout()
  }

  val showJumpToTop by remember {
    derivedStateOf { listState.firstVisibleItemIndex > 3 }
  }

  Box(modifier) {
    LazyColumn(state = listState) { /* article rows */ }
    AnimatedVisibility(showJumpToTop) {
      FloatingActionButton(onClick = { /* scroll to top */ }) { Text("Top") }
    }
  }
}

