@RunWith(AndroidJUnit4::class)
class ComposeStartupBenchmark {
  @get:Rule
  val benchmarkRule = MacrobenchmarkRule()

  @Test
  fun coldStartupNoCompilation() = startup(CompilationMode.None())

  @Test
  fun coldStartupWithBaselineProfile() = startup(
    CompilationMode.Partial(
      baselineProfileMode = BaselineProfileMode.Require
    )
  )

  private fun startup(compilationMode: CompilationMode) = benchmarkRule.measureRepeated(
    packageName = TargetPackage,
    metrics = listOf(StartupTimingMetric()),
    compilationMode = compilationMode,
    startupMode = StartupMode.COLD,
    iterations = 10,
    setupBlock = { pressHome() }
  ) {
    startActivityAndWait()
    device.wait(Until.hasObject(By.res(TargetPackage, "feed")), 5_000)
  }
}

@RunWith(AndroidJUnit4::class)
class FeedScrollBenchmark {
  @get:Rule
  val benchmarkRule = MacrobenchmarkRule()

  @Test
  fun scrollFeedFrames() = benchmarkRule.measureRepeated(
    packageName = TargetPackage,
    metrics = listOf(FrameTimingMetric()),
    compilationMode = CompilationMode.Partial(
      baselineProfileMode = BaselineProfileMode.Require
    ),
    iterations = 10,
    setupBlock = {
