// Compose runtime state for JankStats reports.
@Composable
fun rememberMetricsStateHolder(): PerformanceMetricsState.Holder {
  val view = LocalView.current
  return remember(view) { PerformanceMetricsState.getHolderForHierarchy(view) }
}

@Composable
fun ReportLazyListJankState(listState: LazyListState) {
  val holder = rememberMetricsStateHolder()
  LaunchedEffect(holder, listState) {
    snapshotFlow { listState.isScrollInProgress }
      .collect { scrolling ->
        if (scrolling) holder.state?.putState("LazyList", "Scrolling")
        else holder.state?.removeState("LazyList")
      }
  }
}

