@Composable
fun ExpandableCard(title: String, body: String) {
  var expanded by remember { mutableStateOf(false) }
  val corner by animateDpAsState(
    targetValue = if (expanded) 24.dp else 12.dp,
    animationSpec = spring(stiffness = Spring.StiffnessMediumLow),
    label = "card corner"
  )
  val container by animateColorAsState(
    targetValue = if (expanded) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant,
    label = "card container"
  )

  Card(
    modifier = Modifier
      .fillMaxWidth()
      .animateContentSize()
      .clickable { expanded = !expanded },
    shape = RoundedCornerShape(corner),
    colors = CardDefaults.cardColors(containerColor = container)
  ) {
    Column(Modifier.padding(16.dp)) {
      Text(title, style = MaterialTheme.typography.titleMedium)
      AnimatedVisibility(visible = expanded) {
        Text(body, Modifier.padding(top = 8.dp))
      }
    }
  }
}
